# /etc/nginx/nginx.conf
http {
    # Limit the time allowed for the client to transmit a request header
    # Default is 60s, reduce to prevent slow header attacks
    client_header_timeout 10s;

    # Limit the time allowed for the client to transmit a request body
    # Default is 60s, reduce to prevent slow POST attacks
    client_body_timeout 10s;

    # Set timeout for keep-alive connections
    # Close idle connections quickly to free up resources
    keepalive_timeout 15s;

    # Timeout for reading response from proxied server
    proxy_read_timeout 30s;
    proxy_connect_timeout 10s;
    proxy_send_timeout 10s;

    # Limit request header size to prevent memory exhaustion
    client_header_buffer_size 1k;
    large_client_header_buffers 4 8k;

    # Limit request body size (adjust based on your application)
    client_max_body_size 10M;

    # Reset timeout on slow connections
    send_timeout 10s;

    # Configure connection limits per IP address
    limit_conn_zone $binary_remote_addr zone=conn_limit_per_ip:10m;
    limit_conn conn_limit_per_ip 10;

    # Configure request rate limits
    limit_req_zone $binary_remote_addr zone=req_limit_per_ip:10m rate=10r/s;
    limit_req zone=req_limit_per_ip burst=20 nodelay;

    # Increase worker_connections if needed (default 512)
    events {
        worker_connections 2048;
        use epoll; # Efficient connection processing on Linux
    }

    server {
        listen 80;
        server_name example.com;

        # Apply rate limiting to all locations
        location / {
            limit_conn conn_limit_per_ip 10;
            limit_req zone=req_limit_per_ip burst=5;

            proxy_pass http://backend;

            # Set headers for backend logging
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        }
    }
}

# Configure AWS Application Load Balancer with Slowloris protection
resource "aws_lb" "main" {
  name               = "production-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = aws_subnet.public[*].id

  # Enable deletion protection in production
  enable_deletion_protection = true

  # Enable cross-zone load balancing
  enable_cross_zone_load_balancing = true

  # Enable access logs for security monitoring
  access_logs {
    bucket  = aws_s3_bucket.alb_logs.bucket
    prefix  = "alb-logs"
    enabled = true
  }

  tags = {
    Name        = "production-alb"
    Environment = "production"
  }
}

# Configure target group with health checks
resource "aws_lb_target_group" "web" {
  name     = "web-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  # Health check configuration
  health_check {
    enabled             = true
    healthy_threshold   = 2
    unhealthy_threshold = 3
    timeout             = 5
    interval            = 30
    path                = "/health"
    matcher             = "200"
  }

  # Connection draining
  deregistration_delay = 30

  # Stickiness (optional)
  stickiness {
    type            = "lb_cookie"
    cookie_duration = 86400
    enabled         = true
  }

  tags = {
    Name = "web-target-group"
  }
}

# HTTP listener with idle timeout
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  # Redirect HTTP to HTTPS
  default_action {
    type = "redirect"
    redirect {
      port        = "443"
      protocol    = "HTTPS"
      status_code = "HTTP_301"
    }
  }
}

# HTTPS listener
resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.main.arn
  port              = "443"
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-TLS-1-2-2017-01"
  certificate_arn   = aws_acm_certificate.main.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.web.arn
  }
}

# Configure idle timeout via AWS CLI (Terraform doesn't support this directly)
# Run after terraform apply:
# aws elbv2 modify-load-balancer-attributes \
#   --load-balancer-arn <ALB_ARN> \
#   --attributes Key=idle_timeout.timeout_seconds,Value=10

# Security group for ALB
resource "aws_security_group" "alb" {
  name        = "alb-sg"
  description = "Security group for Application Load Balancer"
  vpc_id      = aws_vpc.main.id

  # Allow HTTP from anywhere
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow HTTPS from anywhere
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-security-group"
  }
}

# WAF Web ACL for additional protection
resource "aws_wafv2_web_acl" "main" {
  name  = "slowloris-protection"
  scope = "REGIONAL"

  default_action {
    allow {}
  }

  # Rate limiting rule
  rule {
    name     = "rate-limit-rule"
    priority = 1

    action {
      block {}
    }

    statement {
      rate_based_statement {
        limit              = 2000
        aggregate_key_type = "IP"
      }
    }

    visibility_config {
      cloudwatch_metrics_enabled = true
      metric_name                = "RateLimitRule"
      sampled_requests_enabled   = true
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "SlowlorisProtection"
    sampled_requests_enabled   = true
  }
}

# Associate WAF with ALB
resource "aws_wafv2_web_acl_association" "main" {
  resource_arn = aws_lb.main.arn
  web_acl_arn  = aws_wafv2_web_acl.main.arn
}

# Configure Cloudflare zone settings
resource "cloudflare_zone_settings_override" "example" {
  zone_id = var.cloudflare_zone_id

  settings {
    # Enable "I'm Under Attack" mode for DDoS protection
    security_level = "high"

    # Enable browser integrity check
    browser_check = "on"

    # Challenge malicious bots
    challenge_ttl = 1800

    # Enable HTTP/2 and HTTP/3
    http2 = "on"
    http3 = "on"

    # Enable automatic HTTPS rewrites
    automatic_https_rewrites = "on"

    # Enable DDoS protection
    security_header {
      enabled = true
    }
  }
}

# Rate limiting rule for Slowloris protection
resource "cloudflare_rate_limit" "slowloris_protection" {
  zone_id = var.cloudflare_zone_id

  threshold   = 60
  period      = 60
  action {
    mode    = "challenge"
    timeout = 3600
  }

  match {
    request {
      url_pattern = "*"
    }
  }

  description = "Slowloris protection - challenge clients with >60 requests/minute"
}

# Firewall rule to block excessive connections
resource "cloudflare_firewall_rule" "block_slow_connections" {
  zone_id     = var.cloudflare_zone_id
  description = "Block IPs with slow connection patterns"
  filter_id   = cloudflare_filter.slow_connections.id
  action      = "challenge"
  priority    = 1
}

resource "cloudflare_filter" "slow_connections" {
  zone_id     = var.cloudflare_zone_id
  description = "Detect slow HTTP connection patterns"
  expression  = "(cf.threat_score gt 30) or (cf.bot_management.score lt 30)"
}

# Advanced rate limiting with custom rules
resource "cloudflare_ruleset" "zone_ddos_protection" {
  zone_id     = var.cloudflare_zone_id
  name        = "DDoS Protection Ruleset"
  description = "Custom DDoS protection including Slowloris"
  kind        = "zone"
  phase       = "ddos_l7"

  rules {
    action = "block"
    expression = "(
      (http.request.uri.path eq \"/api\") and
      (cf.threat_score gt 10)
    )"
    description = "Block suspicious API requests"
    enabled     = true
  }
}

# Page rule for additional security on sensitive endpoints
resource "cloudflare_page_rule" "api_protection" {
  zone_id  = var.cloudflare_zone_id
  target   = "api.example.com/*"
  priority = 1

  actions {
    security_level = "high"
    cache_level    = "bypass"
  }
}

# Custom WAF rule for Slowloris detection
resource "cloudflare_waf_rule" "slowloris_detection" {
  zone_id = var.cloudflare_zone_id
  rule_id = "100000" # Custom rule ID

  mode = "challenge"
}

# Health check for origin server
resource "cloudflare_healthcheck" "origin_health" {
  zone_id = var.cloudflare_zone_id
  name    = "origin-health-check"
  address = "origin.example.com"

  check_regions = [
    "WEU",
    "ENAM"
  ]

  type           = "HTTPS"
  port           = 443
  method         = "GET"
  path           = "/health"
  expected_codes = "200"
  interval       = 60
  retries        = 2
  timeout        = 5

  description = "Monitor origin server availability"
}

const http = require('http');
const express = require('express');
const rateLimit = require('express-rate-limit');
const slowDown = require('express-slow-down');

const app = express();

// Configure rate limiter middleware
const limiter = rateLimit({
  windowMs: 60 * 1000, // 1 minute
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in `RateLimit-*` headers
  legacyHeaders: false, // Disable `X-RateLimit-*` headers
  // Store in Redis for distributed systems
  // store: new RedisStore({ client: redisClient }),
});

// Configure speed limiter (progressive delay)
const speedLimiter = slowDown({
  windowMs: 60 * 1000, // 1 minute
  delayAfter: 50, // Allow 50 requests per minute, then...
  delayMs: 500, // Add 500ms delay per request after delayAfter
  maxDelayMs: 5000, // Max delay of 5 seconds
});

// Apply rate limiting globally
app.use(limiter);
app.use(speedLimiter);

// Parse JSON with size limits
app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: true, limit: '1mb' }));

// Example routes
app.get('/health', (req, res) => {
  res.status(200).json({ status: 'healthy' });
});

app.get('/api/data', (req, res) => {
  res.json({ message: 'API endpoint' });
});

// Create HTTP server with timeout configurations
const server = http.createServer(app);

// Set server timeout (max time for entire request)
server.timeout = 10000; // 10 seconds

// Set header timeout (time to receive complete headers)
server.headersTimeout = 5000; // 5 seconds

// Set keep-alive timeout (idle connection timeout)
server.keepAliveTimeout = 5000; // 5 seconds

// Set request timeout (time to receive complete request)
server.requestTimeout = 10000; // 10 seconds

// Set max header count to prevent header flooding
server.maxHeadersCount = 100;

// Track active connections for monitoring
let activeConnections = 0;
const MAX_CONNECTIONS = 1000;

server.on('connection', (socket) => {
  activeConnections++;

  // Reject new connections if at capacity
  if (activeConnections > MAX_CONNECTIONS) {
    console.warn(`Connection limit reached: ${activeConnections}/${MAX_CONNECTIONS}`);
    socket.destroy();
    return;
  }

  // Set socket timeout
  socket.setTimeout(10000); // 10 seconds

  // Handle socket timeout
  socket.on('timeout', () => {
    console.warn('Socket timeout - destroying connection');
    socket.destroy();
  });

  // Handle socket close
  socket.on('close', () => {
    activeConnections--;
  });

  // Handle socket errors
  socket.on('error', (err) => {
    console.error('Socket error:', err.message);
    socket.destroy();
  });
});

// Monitor connection count
setInterval(() => {
  if (activeConnections > MAX_CONNECTIONS * 0.8) {
    console.warn(`High connection count: ${activeConnections}/${MAX_CONNECTIONS}`);
  }
}, 5000);

// Handle server errors
server.on('error', (err) => {
  console.error('Server error:', err);
});

// Handle client errors (malformed requests)
server.on('clientError', (err, socket) => {
  console.error('Client error:', err.message);
  if (socket.writable) {
    socket.end('HTTP/1.1 400 Bad Request\r\n\r\n');
  }
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, closing server gracefully...');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });

  // Force close after 30 seconds
  setTimeout(() => {
    console.error('Forcing server close after timeout');
    process.exit(1);
  }, 30000);
});

// Start server
const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Max connections: ${MAX_CONNECTIONS}`);
  console.log(`Timeout: ${server.timeout}ms`);
  console.log(`Headers timeout: ${server.headersTimeout}ms`);
});

module.exports = server;

