// Detect slow connection patterns in nginx access logs
GET /nginx-access-*/_search
{
  "query": {
    "bool": {
      "must": [
        { "range": { "@timestamp": { "gte": "now-10m" }}},
        { "range": { "http.request.duration": { "gte": 5000 }}}
      ]
    }
  },
  "aggs": {
    "by_client_ip": {
      "terms": {
        "field": "source.ip",
        "size": 100
      },
      "aggs": {
        "avg_duration": { "avg": { "field": "http.request.duration" }},
        "connection_count": { "cardinality": { "field": "http.request.id" }}
      }
    }
  }
}
